from mcp.server import Server
from mcp.types import Prompt, PromptMessage, TextContent, GetPromptResult
from mcp.types import PromptArgument

app = Server("template-server")

@app.list_prompts()
async def list_prompts():
    return [
        Prompt(
            name="summarise-document",
            description="Summarise a document in bullet points.",
            arguments=[
                PromptArgument(
                    name="document_uri",
                    description="URI of the document resource to summarise.",
                    required=True,
                ),
                PromptArgument(
                    name="max_bullets",
                    description="Maximum number of bullet points (default: 5).",
                    required=False,
                ),
            ],
        )
    ]

@app.get_prompt()
async def get_prompt(name: str, arguments: dict | None) -> GetPromptResult:
    if name == "summarise-document":
        uri = (arguments or {}).get("document_uri", "")
        max_b = (arguments or {}).get("max_bullets", "5")
        return GetPromptResult(
            description="Summarise the document at the given URI.",
            messages=[
                PromptMessage(
                    role="user",
                    content=TextContent(
                        type="text",
                        text=(
                            f"Please read the document at {uri} and summarise it "
                            f"in at most {max_b} concise bullet points."
                        ),
                    ),
                )
            ],
        )
    raise ValueError(f"Unknown prompt: {name}")

# task_server.py — resources + tools for a task management system
from mcp.server import Server
from mcp.types import Resource, Tool, TextContent
import json, mcp.server.stdio

app = Server("task-server")

TASKS: dict[str, dict] = {}   # in-memory store for the example

# ── Resources (read only) ────────────────────────────────────────

@app.list_resources()
async def list_resources():
    return [
        Resource(
            uri="tasks://list",
            name="Task List",
            description="All current tasks with status and priority.",
            mimeType="application/json",
        ),
        *[
            Resource(
                uri=f"tasks://{task_id}",
                name=f"Task {task_id}",
                description=f"Details for task {task_id}.",
                mimeType="application/json",
            )
            for task_id in TASKS
        ],
    ]

@app.read_resource()
async def read_resource(uri: str):
    if uri == "tasks://list":
        return [TextContent(type="text", text=json.dumps(list(TASKS.values()), indent=2))]
    if uri.startswith("tasks://"):
        task_id = uri.removeprefix("tasks://")
        task = TASKS.get(task_id)
        if task:
            return [TextContent(type="text", text=json.dumps(task, indent=2))]
        return [TextContent(type="text", text=json.dumps({"error": f"Task {task_id} not found"}))]
    return [TextContent(type="text", text=json.dumps({"error": f"Unknown URI: {uri}"}))]

# ── Tools (write operations) ─────────────────────────────────────

@app.list_tools()
async def list_tools():
    return [
        Tool(
            name="create_task",
            description=(
                "Create a new task. Use when the user wants to add a task to the list. "
                "Returns the new task ID."
            ),
            inputSchema={
                "type": "object",
                "properties": {
                    "title": {"type": "string", "description": "Task title."},
                    "priority": {
                        "type": "string",
                        "enum": ["low", "medium", "high"],
                        "default": "medium",
                    },
                },
                "required": ["title"],
                "additionalProperties": False,
            },
        ),
        Tool(
            name="complete_task",
            description=(
                "Mark a task as completed. This is permanent. "
                "Always confirm the task ID with the user before calling."
            ),
            inputSchema={
                "type": "object",
                "properties": {
                    "task_id": {"type": "string", "description": "ID of the task to complete."},
                },
                "required": ["task_id"],
                "additionalProperties": False,
            },
        ),
    ]

@app.call_tool()
async def call_tool(name: str, arguments: dict):
    if name == "create_task":
        import uuid
        task_id = str(uuid.uuid4())[:8]
        TASKS[task_id] = {
            "id": task_id,
            "title": arguments["title"],
            "priority": arguments.get("priority", "medium"),
            "status": "open",
        }
        return [TextContent(type="text", text=json.dumps({"task_id": task_id, "status": "created"}))]
    if name == "complete_task":
        task_id = arguments["task_id"]
        if task_id not in TASKS:
            return [TextContent(type="text", text=json.dumps({"error": f"Task {task_id} not found"}))]
        TASKS[task_id]["status"] = "completed"
        return [TextContent(type="text", text=json.dumps({"task_id": task_id, "status": "completed"}))]
    return [TextContent(type="text", text=json.dumps({"error": f"Unknown tool: {name}"}))]

if __name__ == "__main__":
    import asyncio
    asyncio.run(mcp.server.stdio.run(app))
